"use client";

import { type StepperProps, Stepper as StepperRoot } from "./stepper";
import { StepperContent, type StepperContentProps } from "./stepper-content";
import type { StepStatus, SubstepStatus } from "./stepper-context";
import { StepperStep, type StepperStepProps } from "./stepper-step";
import {
  StepperSubstep,
  type StepperSubstepProps,
  type SubstepData,
  substepLabelVariants,
  substepVariants,
} from "./stepper-substep";
import { StepperTrigger, type StepperTriggerProps } from "./stepper-trigger";

/** Root provider (manages expansion + variant) */
const Stepper = Object.assign(StepperRoot, {
  Step: StepperStep,
  Trigger: StepperTrigger,
  Content: StepperContent,
  Substep: StepperSubstep,
});

export { Stepper, type StepperProps };
export { StepperStep, type StepperStepProps, type StepStatus };
export { StepperTrigger, type StepperTriggerProps };
export { StepperContent, type StepperContentProps };
export {
  StepperSubstep,
  substepVariants,
  substepLabelVariants,
  type StepperSubstepProps,
  type SubstepData,
  type SubstepStatus,
};
export type { StepperVariant } from "@/lib/stepper-variants";

"use client";

import {
  Children,
  type ComponentProps,
  isValidElement,
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  useCallback,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useSelectableCollection } from "@/lib/selectable-collection";
import { isStepInteractive, type StepStatus } from "@/lib/step-status";
import { type StepperVariant, stepperRootVariants } from "@/lib/stepper-variants";
import { cn } from "@/lib/utils";
import { StepperContext } from "./stepper-context";
import { StepperStep, type StepperStepProps } from "./stepper-step";
import { StepperTrigger, type StepperTriggerProps } from "./stepper-trigger";
import { useStepperState } from "./use-state";

/** Props for stepper. */
export interface StepperProps extends Omit<ComponentProps<"ol">, "children"> {
  /** Controlled set of currently expanded step ids. */
  expandedIds?: string[];
  /** Initial expanded ids for uncontrolled mode. */
  defaultExpandedIds?: string[];
  /** Fired when the expanded set changes. */
  onExpandedChange?: (ids: string[]) => void;
  /** Visual variant. Controls the indicator glyph and connector treatment across every step. */
  variant?: StepperVariant;
  /** StepperStep children rendered inside an <ol>. */
  children: ReactNode;
}

interface StepDescriptor {
  id: string;
  status: StepStatus;
  label: string | undefined;
  disabled: boolean;
}

type StepRegistrationDescriptor = Omit<StepDescriptor, "disabled">;

// First-render/SSR seed for directly-composed steps: registration effects have
// not run yet, so resolve the active step from the static child tree. Once the
// steps mount, the registrations below are authoritative and also cover steps
// (or triggers) rendered through consumer wrapper components.
function collectStepSeed(children: ReactNode): StepDescriptor[] {
  return Children.toArray(children).flatMap((child) => {
    if (!isValidElement(child) || child.type !== StepperStep) return [];
    const props = child.props as StepperStepProps;
    const trigger = extractTriggerSeed(props.children);
    return [
      {
        id: props.stepId,
        status: props.status,
        label: trigger.label,
        disabled: !isStepInteractive(props.status) || trigger.disabled,
      },
    ];
  });
}

function extractTriggerSeed(children: ReactNode): Pick<StepDescriptor, "label" | "disabled"> {
  for (const child of Children.toArray(children)) {
    if (!isValidElement(child) || child.type !== StepperTrigger) continue;
    const props = child.props as StepperTriggerProps;
    const label =
      typeof props.children === "string" ? props.children.trim() || undefined : undefined;
    return { label, disabled: props.disabled === true };
  }
  return { label: undefined, disabled: false };
}

function isRegisteredStepDisabled(status: StepStatus, element: HTMLElement | null): boolean {
  if (!isStepInteractive(status)) return true;
  return element?.querySelector<HTMLButtonElement>("[data-step-id]")?.disabled === true;
}

/** Root provider (manages expansion + variant) */
export function Stepper({
  expandedIds,
  defaultExpandedIds,
  onExpandedChange,
  variant = "ascii",
  className,
  children,
  onKeyDown,
  ...props
}: StepperProps) {
  const { expandedIds: expanded, toggle } = useStepperState({
    expandedIds,
    defaultExpandedIds,
    onExpandedChange,
  });

  const listRef = useRef<HTMLOListElement>(null);

  // Steps register through the selectable collection (DOM-ordered), while their
  // status/label travel in a side state map keyed by registrationId so the active
  // step and live-region announcement track the rendered order, including steps
  // or triggers composed through consumer wrappers.
  const [stepMeta, setStepMeta] = useState<
    Record<string, { status: StepStatus; label: string | undefined }>
  >({});
  const {
    items: registeredSteps,
    registerItem: registerCollectionItem,
    unregisterItem: unregisterCollectionItem,
  } = useSelectableCollection(listRef);
  const registerStep = useCallback(
    (
      registrationId: string,
      descriptor: StepRegistrationDescriptor,
      element: HTMLElement | null,
    ) => {
      setStepMeta((current) => {
        const existing = current[registrationId];
        if (existing?.status === descriptor.status && existing.label === descriptor.label) {
          return current;
        }
        return {
          ...current,
          [registrationId]: { status: descriptor.status, label: descriptor.label },
        };
      });
      registerCollectionItem(
        registrationId,
        descriptor.id,
        isRegisteredStepDisabled(descriptor.status, element),
        element,
      );
    },
    [registerCollectionItem],
  );
  const unregisterStep = useCallback(
    (registrationId: string) => {
      setStepMeta((current) => {
        if (!(registrationId in current)) return current;
        const { [registrationId]: _removed, ...rest } = current;
        return rest;
      });
      unregisterCollectionItem(registrationId);
    },
    [unregisterCollectionItem],
  );
  const syncRegisteredDisabledState = useCallback(() => {
    for (const item of registeredSteps) {
      const meta = stepMeta[item.id];
      const disabled = isRegisteredStepDisabled(meta?.status ?? "pending", item.element);
      if (item.disabled === disabled) continue;
      registerCollectionItem(item.id, item.value, disabled, item.element);
    }
  }, [registeredSteps, stepMeta, registerCollectionItem]);

  useLayoutEffect(() => {
    syncRegisteredDisabledState();
  }, [syncRegisteredDisabledState]);

  useLayoutEffect(() => {
    const list = listRef.current;
    const View = list?.ownerDocument.defaultView;
    if (!list || !View?.MutationObserver) return;

    const observer = new View.MutationObserver(syncRegisteredDisabledState);
    observer.observe(list, { attributeFilter: ["disabled"], attributes: true, subtree: true });

    return () => observer.disconnect();
  }, [syncRegisteredDisabledState]);

  const seed = useMemo(() => collectStepSeed(children), [children]);
  const steps = useMemo<StepDescriptor[]>(
    () =>
      registeredSteps.length
        ? registeredSteps.map((item) => {
            const meta = stepMeta[item.id];
            return {
              id: item.value,
              status: meta?.status ?? "pending",
              label: meta?.label,
              disabled: item.disabled,
            };
          })
        : seed,
    [registeredSteps, stepMeta, seed],
  );
  const tabTargetId = useMemo(() => {
    const interactive = steps.filter((step) => !step.disabled && isStepInteractive(step.status));
    const target = interactive.find((step) => step.status === "active") ?? interactive[0];
    return target?.id ?? null;
  }, [steps]);

  // Note: Stepper implements its own roving focus instead of using
  // @diffgazer/keys useNavigation. The navigation contract differs: Stepper
  // items use `data-step-id` attribute selectors and filter by
  // `aria-disabled`, while useNavigation uses `data-value` + role-based
  // selectors. Routing through useNavigation would require rewriting the
  // step trigger data contract, which is a public API change.
  const moveFocus = (next: (count: number, current: number) => number) => {
    const list = listRef.current;
    if (!list) return false;
    const triggers = Array.from(list.querySelectorAll<HTMLButtonElement>("[data-step-id]")).filter(
      (el) => el.getAttribute("aria-disabled") !== "true" && !el.disabled,
    );
    if (triggers.length === 0) return false;
    const activeElement = list.ownerDocument.activeElement;
    const ButtonCtor = list.ownerDocument.defaultView?.HTMLButtonElement;
    const currentIndex =
      ButtonCtor && activeElement instanceof ButtonCtor ? triggers.indexOf(activeElement) : -1;
    const nextIndex = next(triggers.length, currentIndex);
    const target = triggers[nextIndex];
    if (!target) return false;
    target.focus();
    return true;
  };

  const handleKeyDown = (event: ReactKeyboardEvent<HTMLOListElement>) => {
    onKeyDown?.(event);
    if (event.defaultPrevented) return;

    const target = event.target as HTMLElement | null;
    // Only react when focus is on one of our triggers (so editable targets
    // in step content keep their native handling).
    if (!target?.hasAttribute("data-step-id")) return;

    switch (event.key) {
      case "ArrowDown":
      case "ArrowRight": {
        if (moveFocus((count, current) => (current === -1 ? 0 : (current + 1) % count))) {
          event.preventDefault();
        }
        return;
      }
      case "ArrowUp":
      case "ArrowLeft": {
        if (
          moveFocus((count, current) =>
            current === -1 ? count - 1 : (current - 1 + count) % count,
          )
        ) {
          event.preventDefault();
        }
        return;
      }
      case "Home": {
        if (moveFocus(() => 0)) event.preventDefault();
        return;
      }
      case "End": {
        if (moveFocus((count) => count - 1)) event.preventDefault();
        return;
      }
    }
  };

  const ctx = useMemo(
    () => ({
      expandedIds: expanded,
      onToggle: toggle,
      variant,
      tabTargetId,
      registerStep,
      unregisterStep,
    }),
    [expanded, toggle, variant, tabTargetId, registerStep, unregisterStep],
  );

  const activeStep = steps.find((step) => step.status === "active");
  const activeIndex = activeStep ? steps.findIndex((step) => step.id === activeStep.id) : -1;

  return (
    <StepperContext value={ctx}>
      {/* biome-ignore lint/a11y/useSemanticElements: this already is an <ol>; the explicit role="list" below restores list semantics that Tailwind preflight strips, and Biome should not suggest swapping the element. */}
      <ol
        ref={listRef}
        // biome-ignore lint/a11y/noRedundantRoles: Tailwind preflight sets list-style:none on <ol>, which drops list semantics in Safari/VoiceOver; role="list" restores them.
        role="list"
        aria-label="Progress steps"
        {...props}
        data-slot="stepper"
        data-variant={variant}
        data-orientation="vertical"
        onKeyDown={handleKeyDown}
        className={cn(stepperRootVariants({ variant }), className)}
      >
        {children}
      </ol>
      <StepperLiveRegion
        label={activeStep?.label}
        position={activeStep ? activeIndex + 1 : null}
        total={steps.length}
      />
    </StepperContext>
  );
}

/** Props for stepper live region. */
interface StepperLiveRegionProps {
  /** Accessible label text. */
  label: string | undefined;
  /** Placement position. */
  position: number | null;
  /** Total item count. */
  total: number;
}

function StepperLiveRegion({ label, position, total }: StepperLiveRegionProps) {
  let message = "";
  if (position !== null) {
    message = label ? `Step ${position} of ${total}: ${label}` : `Step ${position} of ${total}`;
  }

  return (
    // biome-ignore lint/a11y/useSemanticElements: role="status" is the sr-only live region announcing step changes; <output> carries form-association semantics that do not fit here.
    <div role="status" aria-live="polite" className="sr-only">
      {message}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { StepStatus } from "@/lib/step-status";
import type { StepperVariant } from "@/lib/stepper-variants";

export type { StepStatus };

/** Allowed substep status values. */
export type SubstepStatus = "pending" | "active" | "completed" | "error";

/** Context value shared by stepper. */
export interface StepperContextValue {
  /** Controlled set of currently expanded step ids. */
  expandedIds: string[];
  /** Called when an item should toggle. */
  onToggle: (id: string) => void;
  /** Visual variant. Controls the indicator glyph and connector treatment across every step. */
  variant: StepperVariant;
  /** DOM id for tab target. */
  tabTargetId: string | null;
  /** Registers step with stepper. */
  registerStep: (
    registrationId: string,
    descriptor: { id: string; status: StepStatus; label: string | undefined },
    element: HTMLElement | null,
  ) => void;
  /** Unregisters step from stepper. */
  unregisterStep: (registrationId: string) => void;
}

/** React context backing stepper. */
export const StepperContext = createContext<StepperContextValue | undefined>(undefined);

/** Reads the stepper context. */
export function useStepperContext() {
  const context = useContext(StepperContext);
  if (!context) {
    throw new Error("Stepper parts must be used within a Stepper");
  }
  return context;
}

/** Context value shared by stepper step. */
export interface StepperStepContextValue {
  /** Stable identifier matched against expandedIds. */
  stepId: string;
  /** Whether stepper step is expanded. */
  isExpanded: boolean;
  /**
   * Step status. Drives the indicator glyph, label styling, aria-current, aria-disabled, and
   * tab-order eligibility.
   */
  status: StepStatus;
  /** DOM id for trigger. */
  triggerId: string;
  /** DOM id for content. */
  contentId: string;
  /** Whether stepper step has content. */
  hasContent: boolean;
  /** Updates trigger label. */
  setTriggerLabel: (label: string | undefined) => void;
}

/** React context backing stepper step. */
export const StepperStepContext = createContext<StepperStepContextValue | undefined>(undefined);

/** Reads the stepper step context. */
export function useStepperStepContext() {
  const context = useContext(StepperStepContext);
  if (!context) {
    throw new Error("StepperTrigger/StepperContent must be used within StepperStep");
  }
  return context;
}

"use client";

import { useCallback } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";

/** Props for stepper state. */
export interface StepperStateProps {
  /** Controlled set of currently expanded step ids. */
  expandedIds?: string[];
  /** Initial expanded ids for uncontrolled mode. */
  defaultExpandedIds?: string[];
  /** Fired when the expanded set changes. */
  onExpandedChange?: (ids: string[]) => void;
}

/** Provides stepper state behavior. */
export function useStepperState({
  expandedIds,
  defaultExpandedIds,
  onExpandedChange,
}: StepperStateProps) {
  const [expanded, setExpanded] = useControllableState<string[]>({
    value: expandedIds,
    defaultValue: defaultExpandedIds ?? [],
    onChange: onExpandedChange,
  });

  const toggle = useCallback(
    (id: string) => {
      setExpanded((prev) => (prev.includes(id) ? prev.filter((v) => v !== id) : [...prev, id]));
    },
    [setExpanded],
  );

  return { expandedIds: expanded, toggle };
}

"use client";

import {
  Children,
  type ComponentProps,
  isValidElement,
  type ReactNode,
  useId,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { stepperStepVariants } from "@/lib/stepper-variants";
import { cn } from "@/lib/utils";
import { StepperContent } from "./stepper-content";
import { StepperStepContext, type StepStatus, useStepperContext } from "./stepper-context";

/** Props for stepper step. */
export interface StepperStepProps extends Omit<ComponentProps<"li">, "children"> {
  /** Stable identifier matched against expandedIds. */
  stepId: string;
  /**
   * Step status. Drives the indicator glyph, label styling, aria-current, aria-disabled, and
   * tab-order eligibility.
   */
  status: StepStatus;
  /** StepperTrigger and optional StepperContent. */
  children: ReactNode;
  /** Ref forwarded to the underlying element. */
  ref?: ComponentProps<"li">["ref"];
}

function hasStepperContent(children: ReactNode): boolean {
  return Children.toArray(children).some(
    (child) => isValidElement(child) && child.type === StepperContent,
  );
}

/** Individual step with status context. */
export function StepperStep({
  stepId,
  status,
  children,
  className,
  ref,
  ...props
}: StepperStepProps) {
  const { expandedIds, registerStep, unregisterStep } = useStepperContext();
  const isExpanded = expandedIds.includes(stepId);

  const base = useId();
  const registrationId = useId();
  const rootRef = useRef<HTMLLIElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const triggerId = `${base}-trigger`;
  const contentId = `${base}-content`;
  const hasContent = hasStepperContent(children);
  const [triggerLabel, setTriggerLabel] = useState<string | undefined>(undefined);

  useLayoutEffect(() => {
    registerStep(registrationId, { id: stepId, status, label: triggerLabel }, rootRef.current);
    return () => unregisterStep(registrationId);
  }, [registerStep, unregisterStep, registrationId, stepId, status, triggerLabel]);

  const ctx = useMemo(
    () => ({ stepId, isExpanded, status, triggerId, contentId, hasContent, setTriggerLabel }),
    [stepId, isExpanded, status, triggerId, contentId, hasContent],
  );

  return (
    <StepperStepContext value={ctx}>
      <li
        {...props}
        ref={composedRef}
        className={cn(stepperStepVariants(), className)}
        data-state={isExpanded ? "open" : "closed"}
        data-status={status}
      >
        {children}
      </li>
    </StepperStepContext>
  );
}

"use client";

import { type ComponentProps, type ReactNode, useLayoutEffect, useRef } from "react";
import type { StepStatus } from "@/lib/step-status";
import {
  NUMBERED_COMPLETED_GLYPH,
  NUMBERED_DISABLED_GLYPH,
  NUMBERED_ERROR_GLYPH,
  NUMBERED_SKIPPED_GLYPH,
  STEP_INDICATOR_GLYPHS,
  type StepperVariant,
  stepperIndicatorVariants,
  stepperLabelVariants,
  stepperTriggerVariants,
} from "@/lib/stepper-variants";
import { cn } from "@/lib/utils";
import { useStepperContext, useStepperStepContext } from "./stepper-context";

const DEFAULT_STEP_STATUS_LABELS: Record<StepStatus, string> = {
  completed: "DONE",
  active: "RUN",
  pending: "WAIT",
  error: "FAIL",
  skipped: "SKIP",
  disabled: "OFF",
};

const STATUS_SR_PREFIX: Record<StepStatus, string> = {
  completed: "Completed:",
  active: "Current:",
  pending: "Upcoming:",
  error: "Error:",
  skipped: "Skipped:",
  disabled: "Disabled:",
};

/** Props for stepper trigger. */
export interface StepperTriggerProps extends Omit<ComponentProps<"button">, "children" | "type"> {
  /** Step label rendered next to the indicator glyph. */
  children: ReactNode;
  /**
   * Per-status indicator label overrides. Used directly by `variant="tag"`; other variants use
   * these labels as the screen-reader fallback for the indicator glyph.
   */
  statusLabels?: Partial<Record<StepStatus, string>>;
}

/** Clickable step header with indicator and label. */
export function StepperTrigger({
  children,
  className,
  onClick,
  statusLabels,
  disabled: disabledProp,
  ...props
}: StepperTriggerProps) {
  const { onToggle, variant, tabTargetId } = useStepperContext();
  const { stepId, isExpanded, status, triggerId, contentId, hasContent, setTriggerLabel } =
    useStepperStepContext();
  const labelRef = useRef<HTMLSpanElement>(null);

  const isTriggerDisabled = disabledProp === true;
  const isDisabled = isTriggerDisabled || status === "disabled";
  const isInteractive = !isDisabled;
  const tabIndex = tabTargetId === stepId && isInteractive ? 0 : -1;

  const tagLabel = statusLabels?.[status] ?? DEFAULT_STEP_STATUS_LABELS[status];

  // Report the rendered label text up to the step so the Stepper live region can
  // announce it, mirroring the previous static label extraction but resilient to
  // JSX/wrapper-rendered trigger content.
  // biome-ignore lint/correctness/useExhaustiveDependencies: children is the label source; re-read the rendered text whenever it changes.
  useLayoutEffect(() => {
    setTriggerLabel(labelRef.current?.textContent?.trim() || undefined);
  }, [children, setTriggerLabel]);

  return (
    <button
      type="button"
      {...props}
      id={triggerId}
      data-step-id={stepId}
      data-status={status}
      className={cn(stepperTriggerVariants(), className)}
      onClick={(event) => {
        onClick?.(event);
        if (event.defaultPrevented) return;
        if (status === "disabled") return;
        if (hasContent) onToggle(stepId);
      }}
      aria-expanded={hasContent ? isExpanded : undefined}
      aria-controls={hasContent ? contentId : undefined}
      aria-current={status === "active" ? "step" : undefined}
      aria-disabled={status === "disabled" ? true : undefined}
      disabled={isTriggerDisabled ? true : undefined}
      tabIndex={tabIndex}
    >
      <span className={stepperIndicatorVariants({ variant, status })}>
        <span className="sr-only">{STATUS_SR_PREFIX[status]} </span>
        <Glyph variant={variant} status={status} tagLabel={tagLabel} />
      </span>
      <span ref={labelRef} className={stepperLabelVariants({ status })}>
        {children}
      </span>
    </button>
  );
}

/** Props for glyph. */
interface GlyphProps {
  /** Visual variant. Controls the indicator glyph and connector treatment across every step. */
  variant: StepperVariant;
  /** Current status value. */
  status: StepStatus;
  /** Accessible label for tag. */
  tagLabel: string;
}

function Glyph({ variant, status, tagLabel }: GlyphProps) {
  if (variant === "numbered") {
    if (status === "completed") return <>{NUMBERED_COMPLETED_GLYPH}</>;
    if (status === "error") return <>{NUMBERED_ERROR_GLYPH}</>;
    if (status === "skipped") return <>{NUMBERED_SKIPPED_GLYPH}</>;
    if (status === "disabled") return <>{NUMBERED_DISABLED_GLYPH}</>;
    // pending + active render the CSS counter via ::before in the indicator
    // CSS. We attach `data-counter` so the rule selector is variant-scoped.
    return <span data-counter aria-hidden="true" className="contents" />;
  }

  if (variant === "ascii" && status === "active") {
    return (
      <>
        [
        <span
          aria-hidden="true"
          className="motion-safe:animate-[stepper-blink_1s_steps(2)_infinite]"
        >
          ~
        </span>
        ]
      </>
    );
  }

  if (variant === "tag") {
    return <>{tagLabel}</>;
  }

  return <>{STEP_INDICATOR_GLYPHS[variant][status]}</>;
}

/** Returns stepper indicator glyph. */
export function getStepperIndicatorGlyph(variant: StepperVariant, status: StepStatus): string {
  if (variant === "numbered") {
    switch (status) {
      case "completed":
        return NUMBERED_COMPLETED_GLYPH;
      case "error":
        return NUMBERED_ERROR_GLYPH;
      case "skipped":
        return NUMBERED_SKIPPED_GLYPH;
      case "disabled":
        return NUMBERED_DISABLED_GLYPH;
      default:
        return ""; // CSS counter
    }
  }
  if (variant === "ascii" && status === "active") return "[~]";
  if (variant === "tag") return DEFAULT_STEP_STATUS_LABELS[status];
  return STEP_INDICATOR_GLYPHS[variant][status];
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useStepperStepContext } from "./stepper-context";

/** Props for stepper content. */
export interface StepperContentProps extends Omit<ComponentProps<"div">, "children"> {
  /**
   * Expandable content (e.g. nested StepperSubstep rows). Hidden, aria-hidden, and inert when
   * collapsed.
   */
  children: ReactNode;
}

/** Expandable content panel (substeps, custom content) */
export function StepperContent({ children, className, ...props }: StepperContentProps) {
  const { isExpanded, triggerId, contentId } = useStepperStepContext();

  return (
    // biome-ignore lint/a11y/useSemanticElements: role="region" labels the collapsible step panel via aria-labelledby; the grid div owns the expand/collapse animation, so a <section> swap is not appropriate.
    <div
      {...props}
      className={cn(
        "grid transition-[grid-template-rows] duration-200 ease-out motion-reduce:transition-none",
        isExpanded ? "grid-rows-[1fr]" : "grid-rows-[0fr]",
        className,
      )}
      role="region"
      id={contentId}
      aria-labelledby={triggerId}
      aria-hidden={isExpanded ? undefined : true}
      inert={isExpanded ? undefined : true}
    >
      <div className="overflow-hidden min-h-0">
        <div className="pt-2 pl-7" hidden={!isExpanded}>
          {children}
        </div>
      </div>
    </div>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";
import { Badge } from "../badge/badge";
import type { SubstepStatus } from "./stepper-context";

/** Root provider (manages expansion + variant) */
export interface SubstepData {
  /** ID applied to the rendered element. */
  id: string;
  /** tag used by substep. */
  tag: string;
  /** Accessible label text. */
  label: string;
  /** Current status value. */
  status: SubstepStatus;
  /** detail used by substep. */
  detail?: string;
}

/** Class variants for substep. */
export const substepVariants = cva("flex items-center gap-2 py-1 text-sm", {
  variants: {
    status: {
      pending: "text-muted-foreground",
      active: "text-foreground font-medium motion-safe:animate-pulse",
      completed: "text-foreground",
      error: "text-error font-medium",
    },
  },
  defaultVariants: { status: "pending" },
});

/** Root provider (manages expansion + variant) */
export const SUBSTEP_STATUS_BADGE_VARIANTS: Record<
  SubstepStatus,
  "success" | "info" | "error" | "neutral"
> = {
  pending: "neutral",
  active: "info",
  completed: "success",
  error: "error",
};

/** Class variants for substep label. */
export const substepLabelVariants = cva("", {
  variants: {
    status: {
      pending: "",
      active: "text-muted-foreground",
      completed: "text-success",
      error: "text-error",
    },
  },
  defaultVariants: { status: "pending" },
});

/** Props for stepper substep. */
export interface StepperSubstepProps
  extends Omit<ComponentProps<"div">, "children">,
    Omit<SubstepData, "id"> {
  /** Per-status fallback labels shown when detail is omitted. */
  statusLabels?: Partial<Record<SubstepStatus, string>>;
}

/** Nested substep with tag badge and status. */
export function StepperSubstep({
  tag,
  label,
  status,
  detail,
  statusLabels,
  className,
  ...props
}: StepperSubstepProps) {
  const statusText = detail ?? statusLabels?.[status];

  return (
    <div {...props} className={cn(substepVariants({ status }), className)}>
      <Badge
        variant={SUBSTEP_STATUS_BADGE_VARIANTS[status]}
        size="sm"
        className="min-w-[40px] justify-center"
      >
        {tag}
      </Badge>
      <span className="shrink-0">{label}</span>
      {statusText && (
        <span
          title={statusText}
          className={cn(
            "ml-auto min-w-0 truncate text-xs",
            detail ? "text-muted-foreground" : substepLabelVariants({ status }),
          )}
        >
          {statusText}
        </span>
      )}
    </div>
  );
}

/*
 * Stepper variant CSS contract.
 *
 * Three things live in real CSS (not Tailwind utilities):
 *
 *   1. The `ascii` active-state blinking cursor (custom @keyframes). Wrapped
 *      in motion-safe Tailwind utility on the consuming side; the keyframes
 *      themselves are declared here.
 *   2. The `numbered` variant's CSS counter — the digit shown in pending and
 *      active states comes from `counter(step)` rendered through `::before`
 *      on the indicator span. Tailwind's arbitrary value support for
 *      `content-[counter(...)]` is unreliable across compilers.
 *   3. The vertical connector line between steps. Composed via utilities the
 *      connector clamped to a 2px sliver because `bottom: 0` plus a 30px
 *      `<li>` left no room to draw. Real CSS lets the line overshoot the
 *      `<li>` boundary so it visually bridges into the next indicator at any
 *      row height. The `left` offset is variant-specific and centred on the
 *      indicator column width (1ch ASCII → centred on the `x` in `[x]`, 20px
 *      numbered square → centred at 10px, 1ch bullet → centred at 4px).
 */

@keyframes stepper-blink {
  50% {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  /*
   * Keep the cursor visible but stop animating it. The .motion-safe: utility
   * on the consumer prevents the animation property from being set in the
   * first place, but this guard catches any direct usage of the keyframes
   * elsewhere.
   */
  [data-variant="ascii"] [data-stepper-cursor] {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the cursor keyframes regardless of specificity. */
    animation: none !important;
  }
}

/*
 * Numbered indicator: render `counter(step)` for pending and active cells.
 * Completed/error/skipped/disabled render an explicit glyph in JSX and the
 * counter span is absent from the tree.
 *
 * The CSS counter is established on the <ol data-variant="numbered"> via the
 * `[counter-reset:step]` Tailwind utility and incremented on each <li> via
 * `[counter-increment:step]`. This rule paints the digit on the indicator
 * span whose JSX renders an empty `[data-counter]` placeholder.
 */
[data-variant="numbered"] [data-counter]::before {
  content: counter(step);
}

/*
 * Vertical connector — shared geometry for ASCII, numbered, and bullet
 * variants. `tag` and `progress` opt out (no rule). The `<li>` itself is
 * positioned `relative` via the Tailwind base. Scoped to
 * `[data-orientation="vertical"]` so the horizontal stepper's numbered
 * variant (which has its own behind-the-square horizontal bar) is untouched.
 *
 * `top: 36px` clears the indicator glyph (sits at row top with `py-4`, so
 * the glyph bottom edge lands at ~34px and the connector starts ~2px below).
 * `bottom: -8px` overshoots the `<li>` boundary modestly so the line visually
 * bridges into the next step's connector without dominating the row height —
 * the row breathes around a short connector segment rather than a long line.
 * The last step suppresses the connector.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  content: "";
  position: absolute;
  top: 36px;
  bottom: -8px;
  width: 1px;
  background: var(--border);
}

/*
 * Per-variant horizontal alignment of the connector. Each value centres the
 * 1px line on the visual middle of the indicator column.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before {
  /* `[x]` is 3 mono chars wide; centre on the `x` (1.5ch from the left edge). */
  left: calc(1.5ch + 0.5px);
}

[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before {
  /* 20px square indicator → centre at 10px (½px nudge keeps the 1px line crisp). */
  left: 9.5px;
  /* Square bottom sits at ~36px (16px paddingTop + 20px square). Push the
   * connector start 2px below the square so it doesn't paint over the border. */
  top: 38px;
}

[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  /* 1ch indicator → centre at ½ch. Dashed style differentiates the low-chrome variant. */
  left: calc(0.5ch + 0.5px);
  background: transparent;
  border-left: 1px dashed var(--border);
  width: 0;
}

/*
 * Completed steps recolour the connector so a finished segment reads as a
 * filled timeline. Bullet uses `border-left-color` because the connector is
 * a border, not a background.
 */
[data-orientation="vertical"][data-variant="ascii"]
  > li[data-status="completed"]:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"]
  > li[data-status="completed"]:not(:last-child)::before {
  background: var(--success);
}

[data-orientation="vertical"][data-variant="bullet"]
  > li[data-status="completed"]:not(:last-child)::before {
  border-left-color: var(--success);
}
